// --- Configuration ---

const API_BASE_URL = 'https://api.example.com'; // Production API — HTTPS only
const IOT_SUBNET_PREFIX = '192.168.'; // Local IoT device subnet

const DEFAULT_TIMEOUT_MS = 15000;
const IOT_TIMEOUT_MS = 10000;

// --- Token storage (in production, use react-native-keychain or SecureStore) ---

let _authToken = null;

export function setAuthToken(token) {
  _authToken = token;
}

export function clearAuthToken() {
  _authToken = null;
}

// --- Helpers ---

/**
 * Determine whether a URL targets a local IoT device on the trusted subnet.
 */
function isLocalIoTDevice(url) {
  try {
    const parsed = new URL(url);
    return parsed.hostname.startsWith(IOT_SUBNET_PREFIX);
  } catch {
    return false;
  }
}

/**
 * Determine whether a URL uses cleartext HTTP.
 */
function isCleartextHttp(url) {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:';
  } catch {
    return false;
  }
}

/**
 * Validate that a request is allowed under our security policy:
 *   - Production API traffic MUST use HTTPS.
 *   - Cleartext HTTP is ONLY permitted for local IoT devices on 192.168.x.x.
 *   - No other cleartext destinations are allowed.
 */
function validateRequestSecurity(url) {
  const cleartext = isCleartextHttp(url);
  const localIoT = isLocalIoTDevice(url);

  // Rule 1: Production API must always be HTTPS
  if (url.startsWith('http://api.example.com')) {
    throw new SecurityError(
      'Cleartext HTTP to production API is forbidden. Use HTTPS.'
    );
  }

  // Rule 2: Cleartext is only allowed for local IoT devices
  if (cleartext && !localIoT) {
    throw new SecurityError(
      `Cleartext HTTP is only permitted for local IoT devices on subnet ${IOT_SUBNET_PREFIX}x.x. ` +
      `Attempted URL: ${url}`
    );
  }

  // Rule 3: Even for IoT, restrict to the known subnet range
  if (cleartext && localIoT) {
    const parsed = new URL(url);
    const octets = parsed.hostname.split('.');
    if (
      octets.length !== 4 ||
      parseInt(octets[0], 10) !== 192 ||
      parseInt(octets[1], 10) !== 168
    ) {
      throw new SecurityError(
        `IoT device address ${parsed.hostname} does not match expected 192.168.x.x pattern.`
      );
    }
  }
}

// --- Custom Errors ---

export class SecurityError extends Error {
  constructor(message) {
    super(message);
    this.name = 'SecurityError';
  }
}

export class NetworkError extends Error {
  constructor(message, statusCode = null, responseBody = null) {
    super(message);
    this.name = 'NetworkError';
    this.statusCode = statusCode;
    this.responseBody = responseBody;
  }
}

export class TimeoutError extends Error {
  constructor(message) {
    super(message);
    this.name = 'TimeoutError';
  }
}

// --- Timeout wrapper ---

function fetchWithTimeout(url, options, timeoutMs) {
  return new Promise((resolve, reject) => {
    const controller = new AbortController();
    const timer = setTimeout(() => {
      controller.abort();
      reject(new TimeoutError(`Request to ${url} timed out after ${timeoutMs}ms`));
    }, timeoutMs);

    fetch(url, { ...options, signal: controller.signal })
      .then((response) => {
        clearTimeout(timer);
        resolve(response);
      })
      .catch((err) => {
        clearTimeout(timer);
        if (err.name === 'AbortError') {
          reject(new TimeoutError(`Request to ${url} was aborted / timed out`));
        } else {
          reject(err);
        }
      });
  });
}

// --- Core request function ---

/**
 * Make an HTTP(S) request with full security validation.
 *
 * @param {string}  url              Full URL
 * @param {object}  options
 * @param {string}  options.method   HTTP method (default GET)
 * @param {object}  options.headers  Additional headers
 * @param {*}       options.body     Request body (will be JSON-stringified if object)
 * @param {number}  options.timeout  Timeout in ms
 * @param {boolean} options.raw      If true, return the raw Response object
 * @returns {Promise<object|Response>}
 */
async function request(url, options = {}) {
  const {
    method = 'GET',
    headers = {},
    body = undefined,
    timeout = undefined,
    raw = false,
  } = options;

  // ---- Security gate ----
  validateRequestSecurity(url);

  // ---- Build headers ----
  const isIoT = isLocalIoTDevice(url);
  const finalHeaders = {
    'Accept': 'application/json',
    ...headers,
  };

  // Attach auth token ONLY to production API requests (never leak to IoT devices)
  if (!isIoT && _authToken) {
    finalHeaders['Authorization'] = `Bearer ${_authToken}`;
  }

  // Set Content-Type for requests with a body
  if (body !== undefined && !finalHeaders['Content-Type']) {
    finalHeaders['Content-Type'] = 'application/json';
  }

  // ---- Build fetch options ----
  const fetchOptions = {
    method,
    headers: finalHeaders,
  };

  if (body !== undefined) {
    fetchOptions.body =
      typeof body === 'string' ? body : JSON.stringify(body);
  }

  // ---- Determine timeout ----
  const effectiveTimeout = timeout || (isIoT ? IOT_TIMEOUT_MS : DEFAULT_TIMEOUT_MS);

  // ---- Execute ----
  let response;
  try {
    response = await fetchWithTimeout(url, fetchOptions, effectiveTimeout);
  } catch (err) {
    if (err instanceof TimeoutError || err instanceof SecurityError) {
      throw err;
    }
    throw new NetworkError(`Network request failed: ${err.message}`);
  }

  if (raw) {
    return response;
  }

  // ---- Parse response ----
  const contentType = response.headers.get('content-type') || '';
  let responseBody;

  if (contentType.includes('application/json')) {
    try {
      responseBody = await response.json();
    } catch {
      responseBody = null;
    }
  } else {
    responseBody = await response.text();
  }

  if (!response.ok) {
    throw new NetworkError(
      `HTTP ${response.status} ${response.statusText} — ${method} ${url}`,
      response.status,
      responseBody
    );
  }

  return responseBody;
}

