export const IoTClient = {
  /**
   * Build the base URL for a local IoT device.
   * Only cleartext HTTP on 192.168.x.x is permitted.
   */
  _baseUrl(deviceIp, port = 80) {
    if (!deviceIp.startsWith(IOT_SUBNET_PREFIX)) {
      throw new SecurityError(
        `IoT device IP must be on subnet ${IOT_SUBNET_PREFIX}x.x. Got: ${deviceIp}`
      );
    }
    return `http://${deviceIp}:${port}`;
  },

  /**
   * Generic request to a local IoT device.
   */
  request(deviceIp, path = '/', options = {}) {
    const { port = 80, ...rest } = options;
    const url = `${this._baseUrl(deviceIp, port)}${path}`;
    return request(url, rest);
  },

  get(deviceIp, path = '/', options = {}) {
    return this.request(deviceIp, path, { ...options, method: 'GET' });
  },

  post(deviceIp, path, body, options = {}) {
    return this.request(deviceIp, path, { ...options, method: 'POST', body });
  },

  put(deviceIp, path, body, options = {}) {
    return this.request(deviceIp, path, { ...options, method: 'PUT', body });
  },

  /**
   * Discover / ping a device to check if it's reachable.
   */
  async ping(deviceIp, options = {}) {
    const { port = 80, timeout = 3000 } = options;
    try {
      const url = `${this._baseUrl(deviceIp, port)}/`;
      await request(url, { method: 'GET', timeout, raw: true });
      return { reachable: true, ip: deviceIp, port };
    } catch {
      return { reachable: false, ip: deviceIp, port };
    }
  },

  /**
   * Scan a range of IPs on the local subnet for reachable devices.
   * Example: scanSubnet('192.168.1', 1, 254)
   */
  async scanSubnet(subnetPrefix, startHost = 1, endHost = 254, options = {}) {
    const { port = 80, concurrency = 20 } = options;
    const ips = [];
    for (let i = startHost; i <= endHost; i++) {
      ips.push(`${subnetPrefix}.${i}`);
    }

    const results = [];
    // Process in batches to avoid overwhelming the network
    for (let i = 0; i < ips.length; i += concurrency) {
      const batch = ips.slice(i, i + concurrency);
      const batchResults = await Promise.all(
        batch.map((ip) => this.ping(ip, { port, timeout: 2000 }))
      );
      results.push(...batchResults);
    }

    return results.filter((r) => r.reachable);
  },
};

